const symbols = $input.all().map(i => i.json.symbol);
// Always include NIFTY for broad market options analysis
const allSymbols = ['NIFTY', ...symbols.filter(s => s !== 'NIFTY')];
return [{ json: { symbols: allSymbols } }];

// Analyze NIFTY option chain: PCR, Max Pain, Max OI strikes
const ocData = $input.first().json;

if (!ocData || !ocData.records) {
  return [{ json: { symbol: 'NIFTY', error: 'Option chain data unavailable' } }];
}

const data = ocData.records.data || [];
const spotPrice = ocData.records.underlyingValue || 0;

let totalCallOI = 0, totalPutOI = 0;
let maxCallOI = 0, maxCallOIStrike = 0;
let maxPutOI = 0, maxPutOIStrike = 0;
const strikes = [];

for (const row of data) {
  const strike = row.strikePrice;
  const callOI = row.CE?.openInterest || 0;
  const putOI = row.PE?.openInterest || 0;
  const callIV = row.CE?.impliedVolatility || 0;
  const putIV = row.PE?.impliedVolatility || 0;

  totalCallOI += callOI;
  totalPutOI += putOI;

  if (callOI > maxCallOI) { maxCallOI = callOI; maxCallOIStrike = strike; }
  if (putOI > maxPutOI) { maxPutOI = putOI; maxPutOIStrike = strike; }

  strikes.push({ strike, callOI, putOI, callIV, putIV });
}

const pcr = totalCallOI > 0 ? (totalPutOI / totalCallOI).toFixed(2) : 0;

// Max Pain calculation
let minPain = Infinity, maxPainStrike = 0;
for (const s of strikes) {
  let pain = 0;
  for (const other of strikes) {
    if (other.strike < s.strike) pain += other.callOI * (s.strike - other.strike);
    if (other.strike > s.strike) pain += other.putOI * (other.strike - s.strike);
  }
  if (pain < minPain) { minPain = pain; maxPainStrike = s.strike; }
}

// PCR interpretation
let pcrSignal = 'neutral';
if (parseFloat(pcr) > 1.2) pcrSignal = 'bullish (heavy put writing = support)';
else if (parseFloat(pcr) < 0.8) pcrSignal = 'bearish (heavy call writing = resistance)';

return [{
  json: {
    symbol: 'NIFTY',
    spot_price: spotPrice,
    pcr: parseFloat(pcr),
    pcr_signal: pcrSignal,
    max_pain: maxPainStrike,
    max_call_oi_strike: maxCallOIStrike,
    max_put_oi_strike: maxPutOIStrike,
    expected_range: `${maxPutOIStrike} - ${maxCallOIStrike}`,
    total_call_oi: totalCallOI,
    total_put_oi: totalPutOI,
    top_strikes: strikes.sort((a,b) => (b.callOI + b.putOI) - (a.callOI + a.putOI)).slice(0, 10)
  }
}];

// Build NewsAPI request for all portfolio stocks
const symbols = $('Add NIFTY to List').first().json.symbols.filter(s => s !== 'NIFTY');
const query = symbols.slice(0, 10).join(' OR '); // NewsAPI limit
return [{ json: { query: query, symbols: symbols } }];

// Combine all data: options + news sentiment + corporate actions with error handling
let niftyOptions = {};
let sentimentResponse = {};
let corporateActions = {};
let newsArticles = {};

try { niftyOptions = $('Analyze NIFTY Options').first().json; } catch (e) { niftyOptions = { symbol: 'NIFTY', error: 'Options data unavailable' }; }
try { sentimentResponse = $('Claude: Sentiment Score').first().json; } catch (e) { sentimentResponse = { content: [{ type: 'text', text: '[]' }] }; }
try { corporateActions = $('NSE: Corporate Actions').first().json; } catch (e) { corporateActions = { error: 'Corporate actions unavailable' }; }
try { newsArticles = $('NewsAPI: Stock News').first().json; } catch (e) { newsArticles = { articles: [] }; }

// Parse sentiment
let sentiment = [];
try {
  const content = sentimentResponse.content || [];
  const text = content.filter(c => c.type === 'text').map(c => c.text).join('');
  const clean = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  sentiment = JSON.parse(clean);
} catch (e) {
  sentiment = [{ parse_error: e.message }];
}

const dateStr = new Date().toISOString().split('T')[0];

const combinedData = {
  nifty_options: niftyOptions,
  news_sentiment: sentiment,
  corporate_actions: corporateActions,
  news_articles: (newsArticles.articles || []).slice(0, 10).map(a => ({
    title: a.title,
    source: a.source?.name,
    publishedAt: a.publishedAt
  })),
  collected_at: new Date().toISOString()
};

return [{ json: { data: combinedData, date: dateStr } }];
